/**
 * @suppress
 */
public object FfiConverterTypeE2eeEngine: FfiConverter<E2eeEngine, Pointer> {

    override fun lower(value: E2eeEngine): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): E2eeEngine {
        return E2eeEngine(value)
    }

    override fun read(buf: ByteBuffer): E2eeEngine {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: E2eeEngine) = 8UL

    override fun write(value: E2eeEngine, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}


// This template implements a class for working with a Rust struct via a Pointer/Arc<T>
// to the live Rust struct on the other side of the FFI.
//
// Each instance implements core operations for working with the Rust `Arc<T>` and the
// Kotlin Pointer to work with the live Rust struct on the other side of the FFI.
//
// There's some subtlety here, because we have to be careful not to operate on a Rust
// struct after it has been dropped, and because we must expose a public API for freeing
// theq Kotlin wrapper object in lieu of reliable finalizers. The core requirements are:
//
//   * Each instance holds an opaque pointer to the underlying Rust struct.
//     Method calls need to read this pointer from the object's state and pass it in to
//     the Rust FFI.
//
//   * When an instance is no longer needed, its pointer should be passed to a
//     special destructor function provided by the Rust FFI, which will drop the
//     underlying Rust struct.
//
//   * Given an instance, calling code is expected to call the special
//     `destroy` method in order to free it after use, either by calling it explicitly
//     or by using a higher-level helper like the `use` method. Failing to do so risks
//     leaking the underlying Rust struct.
//
//   * We can't assume that calling code will do the right thing, and must be prepared
//     to handle Kotlin method calls executing concurrently with or even after a call to
//     `destroy`, and to handle multiple (possibly concurrent!) calls to `destroy`.
//
//   * We must never allow Rust code to operate on the underlying Rust struct after
//     the destructor has been called, and must never call the destructor more than once.
//     Doing so may trigger memory unsafety.
//
//   * To mitigate many of the risks of leaking memory and use-after-free unsafety, a `Cleaner`
//     is implemented to call the destructor when the Kotlin object becomes unreachable.
//     This is done in a background thread. This is not a panacea, and client code should be aware that
//      1. the thread may starve if some there are objects that have poorly performing
//     `drop` methods or do significant work in their `drop` methods.
//      2. the thread is shared across the whole library. This can be tuned by using `android_cleaner = true`,
//         or `android = true` in the [`kotlin` section of the `uniffi.toml` file](https://mozilla.github.io/uniffi-rs/kotlin/configuration.html).
//
// If we try to implement this with mutual exclusion on access to the pointer, there is the
// possibility of a race between a method call and a concurrent call to `destroy`:
//
//    * Thread A starts a method call, reads the value of the pointer, but is interrupted
//      before it can pass the pointer over the FFI to Rust.
//    * Thread B calls `destroy` and frees the underlying Rust struct.
//    * Thread A resumes, passing the already-read pointer value to Rust and triggering
//      a use-after-free.
//
// One possible solution would be to use a `ReadWriteLock`, with each method call taking
// a read lock (and thus allowed to run concurrently) and the special `destroy` method
// taking a write lock (and thus blocking on live method calls). However, we aim not to
// generate methods with any hidden blocking semantics, and a `destroy` method that might
// block if called incorrectly seems to meet that bar.
//
// So, we achieve our goals by giving each instance an associated `AtomicLong` counter to track
// the number of in-flight method calls, and an `AtomicBoolean` flag to indicate whether `destroy`
// has been called. These are updated according to the following rules:
//
//    * The initial value of the counter is 1, indicating a live object with no in-flight calls.
//      The initial value for the flag is false.
//
//    * At the start of each method call, we atomically check the counter.
//      If it is 0 then the underlying Rust struct has already been destroyed and the call is aborted.
//      If it is nonzero them we atomically increment it by 1 and proceed with the method call.
//
//    * At the end of each method call, we atomically decrement and check the counter.
//      If it has reached zero then we destroy the underlying Rust struct.
//
//    * When `destroy` is called, we atomically flip the flag from false to true.
//      If the flag was already true we silently fail.
//      Otherwise we atomically decrement and check the counter.
//      If it has reached zero then we destroy the underlying Rust struct.
//
// Astute readers may observe that this all sounds very similar to the way that Rust's `Arc<T>` works,
// and indeed it is, with the addition of a flag to guard against multiple calls to `destroy`.
//
// The overall effect is that the underlying Rust struct is destroyed only when `destroy` has been
// called *and* all in-flight method calls have completed, avoiding violating any of the expectations
// of the underlying Rust code.
//
// This makes a cleaner a better alternative to _not_ calling `destroy()` as
// and when the object is finished with, but the abstraction is not perfect: if the Rust object's `drop`
// method is slow, and/or there are many objects to cleanup, and it's on a low end Android device, then the cleaner
// thread may be starved, and the app will leak memory.
//
// In this case, `destroy`ing manually may be a better solution.
//
// The cleaner can live side by side with the manual calling of `destroy`. In the order of responsiveness, uniffi objects
// with Rust peers are reclaimed:
//
// 1. By calling the `destroy` method of the object, which calls `rustObject.free()`. If that doesn't happen:
// 2. When the object becomes unreachable, AND the Cleaner thread gets to call `rustObject.free()`. If the thread is starved then:
// 3. The memory is reclaimed when the process terminates.
//
// [1] https://stackoverflow.com/questions/24376768/can-java-finalize-an-object-when-it-is-still-in-scope/24380219
//


/**
 * Platform key protection, implemented by the Android shell over an
 * Android-Keystore-resident wrapping key (see `KeystoreProtector.kt`).
 *
 * Contract (identical to the core trait this adapts): fail closed — an
 * unwrap failure is an error, NEVER a silent regeneration (a regenerated
 * key would orphan the encrypted store).
 */
public interface KeyProtector {
    
    fun `protect`(`plaintext`: kotlin.ByteArray): kotlin.ByteArray
    
    fun `unprotect`(`blob`: kotlin.ByteArray): kotlin.ByteArray
    
    companion object
}

/**
 * Platform key protection, implemented by the Android shell over an
 * Android-Keystore-resident wrapping key (see `KeystoreProtector.kt`).
 *
 * Contract (identical to the core trait this adapts): fail closed — an
 * unwrap failure is an error, NEVER a silent regeneration (a regenerated
 * key would orphan the encrypted store).
 */
open class KeyProtectorImpl: Disposable, AutoCloseable, KeyProtector
{

    constructor(pointer: Pointer) {
        this.pointer = pointer
        this.cleanable = UniffiLib.CLEANER.register(this, UniffiCleanAction(pointer))
    }

    /**
     * This constructor can be used to instantiate a fake object. Only used for tests. Any
     * attempt to actually use an object constructed this way will fail as there is no
     * connected Rust object.
     */
    @Suppress("UNUSED_PARAMETER")
    constructor(noPointer: NoPointer) {
        this.pointer = null
        this.cleanable = UniffiLib.CLEANER.register(this, UniffiCleanAction(pointer))
    }

    protected val pointer: Pointer?
    protected val cleanable: UniffiCleaner.Cleanable

    private val wasDestroyed = AtomicBoolean(false)
    private val callCounter = AtomicLong(1)

    override fun destroy() {
        // Only allow a single call to this method.
        // TODO: maybe we should log a warning if called more than once?
        if (this.wasDestroyed.compareAndSet(false, true)) {
            // This decrement always matches the initial count of 1 given at creation time.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable.clean()
            }
        }
    }

    @Synchronized
    override fun close() {
        this.destroy()
    }

    internal inline fun <R> callWithPointer(block: (ptr: Pointer) -> R): R {
        // Check and increment the call counter, to keep the object alive.
        // This needs a compare-and-set retry loop in case of concurrent updates.
        do {
            val c = this.callCounter.get()
            if (c == 0L) {
                throw IllegalStateException("${this.javaClass.simpleName} object has already been destroyed")
            }
            if (c == Long.MAX_VALUE) {
                throw IllegalStateException("${this.javaClass.simpleName} call counter would overflow")
            }
        } while (! this.callCounter.compareAndSet(c, c + 1L))
        // Now we can safely do the method call without the pointer being freed concurrently.
        try {
            return block(this.uniffiClonePointer())
        } finally {
            // This decrement always matches the increment we performed above.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable.clean()
            }
        }
    }

    // Use a static inner class instead of a closure so as not to accidentally
    // capture `this` as part of the cleanable's action.
    private class UniffiCleanAction(private val pointer: Pointer?) : Runnable {
        override fun run() {
            pointer?.let { ptr ->
                uniffiRustCall { status ->
                    UniffiLib.INSTANCE.uniffi_acutest_e2ee_fn_free_keyprotector(ptr, status)
                }
            }
        }
    }

    fun uniffiClonePointer(): Pointer {
        return uniffiRustCall() { status ->
            UniffiLib.INSTANCE.uniffi_acutest_e2ee_fn_clone_keyprotector(pointer!!, status)
        }
    }

    
    @Throws(ProtectorException::class)override fun `protect`(`plaintext`: kotlin.ByteArray): kotlin.ByteArray {
            return FfiConverterByteArray.lift(
    callWithPointer {
    uniffiRustCallWithError(ProtectorException) { _status ->
    UniffiLib.INSTANCE.uniffi_acutest_e2ee_fn_method_keyprotector_protect(
        it, FfiConverterByteArray.lower(`plaintext`),_status)
}
    }
    )
    }
    

    
    @Throws(ProtectorException::class)override fun `unprotect`(`blob`: kotlin.ByteArray): kotlin.ByteArray {
            return FfiConverterByteArray.lift(
    callWithPointer {
    uniffiRustCallWithError(ProtectorException) { _status ->
    UniffiLib.INSTANCE.uniffi_acutest_e2ee_fn_method_keyprotector_unprotect(
        it, FfiConverterByteArray.lower(`blob`),_status)
}
    }
    )
    }
    

    

    
    
    companion object
    
}


// Put the implementation in an object so we don't pollute the top-level namespace
internal object uniffiCallbackInterfaceKeyProtector {
    internal object `protect`: UniffiCallbackInterfaceKeyProtectorMethod0 {
        override fun callback(`uniffiHandle`: Long,`plaintext`: RustBuffer.ByValue,`uniffiOutReturn`: RustBuffer,uniffiCallStatus: UniffiRustCallStatus,) {
            val uniffiObj = FfiConverterTypeKeyProtector.handleMap.get(uniffiHandle)
            val makeCall = { ->
                uniffiObj.`protect`(
                    FfiConverterByteArray.lift(`plaintext`),
                )
            }
            val writeReturn = { value: kotlin.ByteArray -> uniffiOutReturn.setValue(FfiConverterByteArray.lower(value)) }
            uniffiTraitInterfaceCallWithError(
                uniffiCallStatus,
                makeCall,
                writeReturn,
                { e: ProtectorException -> FfiConverterTypeProtectorError.lower(e) }
            )
        }
    }
    internal object `unprotect`: UniffiCallbackInterfaceKeyProtectorMethod1 {
        override fun callback(`uniffiHandle`: Long,`blob`: RustBuffer.ByValue,`uniffiOutReturn`: RustBuffer,uniffiCallStatus: UniffiRustCallStatus,) {
            val uniffiObj = FfiConverterTypeKeyProtector.handleMap.get(uniffiHandle)
            val makeCall = { ->
                uniffiObj.`unprotect`(
                    FfiConverterByteArray.lift(`blob`),
                )
            }
            val writeReturn = { value: kotlin.ByteArray -> uniffiOutReturn.setValue(FfiConverterByteArray.lower(value)) }
            uniffiTraitInterfaceCallWithError(
                uniffiCallStatus,
                makeCall,
                writeReturn,
                { e: ProtectorException -> FfiConverterTypeProtectorError.lower(e) }
            )
        }
    }

    internal object uniffiFree: UniffiCallbackInterfaceFree {
        override fun callback(handle: Long) {
            FfiConverterTypeKeyProtector.handleMap.remove(handle)
        }
    }

    internal var vtable = UniffiVTableCallbackInterfaceKeyProtector.UniffiByValue(
        `protect`,
        `unprotect`,
        uniffiFree,
    )

    // Registers the foreign callback with the Rust side.
    // This method is generated for each callback interface.
    internal fun register(lib: UniffiLib) {
        lib.uniffi_acutest_e2ee_fn_init_callback_vtable_keyprotector(vtable)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeKeyProtector: FfiConverter<KeyProtector, Pointer> {
    internal val handleMap = UniffiHandleMap<KeyProtector>()

    override fun lower(value: KeyProtector): Pointer {
        return Pointer(handleMap.insert(value))
    }

    override fun lift(value: Pointer): KeyProtector {
        return KeyProtectorImpl(value)
    }

    override fun read(buf: ByteBuffer): KeyProtector {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: KeyProtector) = 8UL

    override fun write(value: KeyProtector, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



/**
 * Decrypted attachment content for the WebView interceptor (the Android
 * analog of the desktop `e2ee-att` protocol handler). `mime` has ALREADY
 * been degraded by the same whitelist the desktop handler applies — the
 * Kotlin side must serve it verbatim and add `no-store` / `nosniff` /
 * sandboxing headers, never re-derive a type from the name or bytes.
 */
data class AttachmentContent (
    var `data`: kotlin.ByteArray, 
    var `mime`: kotlin.String
) {
    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeAttachmentContent: FfiConverterRustBuffer<AttachmentContent> {
    override fun read(buf: ByteBuffer): AttachmentContent {
        return AttachmentContent(
            FfiConverterByteArray.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: AttachmentContent) = (
            FfiConverterByteArray.allocationSize(value.`data`) +
            FfiConverterString.allocationSize(value.`mime`)
    )

    override fun write(value: AttachmentContent, buf: ByteBuffer) {
            FfiConverterByteArray.write(value.`data`, buf)
            FfiConverterString.write(value.`mime`, buf)
    }
}





/**
 * FFI error. `flat_error`: only the Display string (the core error's JSON)
 * crosses to Kotlin, which forwards it opaquely to the webview bridge —
 * the same typed, scrubbed payload the desktop IPC rejects with.
 */
sealed class E2eeException(message: String): kotlin.Exception(message) {
        
        class Failure(message: String) : E2eeException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<E2eeException> {
        override fun lift(error_buf: RustBuffer.ByValue): E2eeException = FfiConverterTypeE2eeError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeE2eeError : FfiConverterRustBuffer<E2eeException> {
    override fun read(buf: ByteBuffer): E2eeException {
        
            return when(buf.getInt()) {
            1 -> E2eeException.Failure(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: E2eeException): ULong {
        return 4UL
    }

    override fun write(value: E2eeException, buf: ByteBuffer) {
        when(value) {
            is E2eeException.Failure -> {
                buf.putInt(1)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





/**
 * Error type of the FOREIGN [`KeyProtector`] callback (Kotlin → Rust).
 *
 * This is deliberately NOT `flat_error`: uniffi can only LIFT (foreign →
 * Rust) a fielded error enum, and a foreign callback that throws must be
 * lifted back into Rust. A `flat_error` here aborts the process with
 * "Can't lift flat errors" the first time the protector fails (found on
 * device, slice-4). It carries no detail by design — every protector
 * failure collapses to the core's scrubbed `Error::Protector`.
 */
sealed class ProtectorException: kotlin.Exception() {
    
    class Failed(
        ) : ProtectorException() {
        override val message
            get() = ""
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ProtectorException> {
        override fun lift(error_buf: RustBuffer.ByValue): ProtectorException = FfiConverterTypeProtectorError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeProtectorError : FfiConverterRustBuffer<ProtectorException> {
    override fun read(buf: ByteBuffer): ProtectorException {
        

        return when(buf.getInt()) {
            1 -> ProtectorException.Failed()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ProtectorException): ULong {
        return when(value) {
            is ProtectorException.Failed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: ProtectorException, buf: ByteBuffer) {
        when(value) {
            is ProtectorException.Failed -> {
                buf.putInt(1)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalString: FfiConverterRustBuffer<kotlin.String?> {
    override fun read(buf: ByteBuffer): kotlin.String? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterString.read(buf)
    }

    override fun allocationSize(value: kotlin.String?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterString.allocationSize(value)
        }
    }

    override fun write(value: kotlin.String?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterString.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterSequenceString: FfiConverterRustBuffer<List<kotlin.String>> {
    override fun read(buf: ByteBuffer): List<kotlin.String> {
        val len = buf.getInt()
        return List<kotlin.String>(len) {
            FfiConverterString.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.String>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterString.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.String>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterString.write(it, buf)
        }
    }
}

